// Validation helper module
// Provides reusable field validators and a composite validate() utility.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ---------------------------------------------------------------------------
// Individual field validators
// Each returns an error message string on failure, or null on success.
// ---------------------------------------------------------------------------

/**
 * Validates that a value is present (not undefined, null, or empty string).
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return `"${fieldName}" is required`;
  }
  return null;
}

/**
 * Validates that a value is a finite integer (accepts numeric strings when
 * the value originates from URL/query params).
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateNumericId(value, fieldName) {
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `"${fieldName}" must be a positive integer`;
  }
  return null;
}

/**
 * Validates that a value is a non-empty string.
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateString(value, fieldName) {
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  return null;
}

/**
 * Validates string length falls within [min, max] (inclusive).
 * Assumes the value is already confirmed to be a string.
 * @param {string} value
 * @param {string} fieldName
 * @param {number} min
 * @param {number} max
 * @returns {string|null}
 */
function validateStringLength(value, fieldName, min, max) {
  const len = value.length;
  if (len < min || len > max) {
    return `"${fieldName}" must be between ${min} and ${max} characters`;
  }
  return null;
}

/**
 * Validates that a value matches a basic email format and does not exceed
 * the RFC 5321 maximum address length of 254 characters.
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateEmail(value, fieldName) {
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  if (value.length > 254) {
    return `"${fieldName}" must not exceed 254 characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `"${fieldName}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite schema validator
// ---------------------------------------------------------------------------

/**
 * Runs a list of validator functions and collects all error messages.
 *
 * @param {Array<() => string|null>} validators  Zero-argument thunks that
 *   each return a string error message or null.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validate(validators) {
  const errors = validators
    .map((fn) => fn())
    .filter((msg) => msg !== null);
  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// High-level schema helpers used by route handlers
// ---------------------------------------------------------------------------

/**
 * Validates the URL parameter `id` (string from Express params).
 * @param {string} id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateIdParam(id) {
  return validate([
    () => validateRequired(id, 'id'),
    () => validateNumericId(id, 'id'),
  ]);
}

/**
 * Validates the request body for creating a new user.
 * All fields (name, email) are required.
 * @param {{ name?: *, email?: * }} body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUserBody(body) {
  const { name, email } = body;
  return validate([
    () => validateRequired(name, 'name'),
    () => name !== undefined && name !== null ? validateString(name, 'name') : null,
    () =>
      typeof name === 'string'
        ? validateStringLength(name, 'name', 1, 100)
        : null,
    () => validateRequired(email, 'email'),
    () => (email !== undefined && email !== null ? validateEmail(email, 'email') : null),
  ]);
}

/**
 * Validates the request body for updating an existing user.
 * At least one field must be provided; each provided field is fully validated.
 * @param {{ name?: *, email?: * }} body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUserBody(body) {
  const { name, email } = body;
  const errors = [];

  if (name === undefined && email === undefined) {
    errors.push('At least one field ("name" or "email") must be provided');
    return { valid: false, errors };
  }

  if (name !== undefined) {
    const typeErr = validateString(name, 'name');
    if (typeErr) {
      errors.push(typeErr);
    } else {
      const lenErr = validateStringLength(name, 'name', 1, 100);
      if (lenErr) errors.push(lenErr);
    }
  }

  if (email !== undefined) {
    const emailErr = validateEmail(email, 'email');
    if (emailErr) errors.push(emailErr);
  }

  return { valid: errors.length === 0, errors };
}

module.exports = {
  // Primitive validators (exported for unit testing)
  validateRequired,
  validateNumericId,
  validateString,
  validateStringLength,
  validateEmail,
  validate,
  // Schema-level helpers used by route handlers
  validateIdParam,
  validateCreateUserBody,
  validateUpdateUserBody,
};

