/**
 * Validation helper module.
 * Each exported function returns an array of error strings.
 * An empty array means all checks passed.
 */

/**
 * Validate that every key listed in `fields` is present and non-empty in `source`.
 * @param {object} source  - The object to inspect (req.body, req.params, etc.)
 * @param {string[]} fields - Field names that must be present.
 * @returns {string[]} Errors, one per missing/empty field.
 */
function validateRequired(source, fields) {
  const errors = [];
  for (const field of fields) {
    if (source[field] === undefined || source[field] === null || source[field] === '') {
      errors.push(`"${field}" is required`);
    }
  }
  return errors;
}

/**
 * Validate that `value` is a positive integer (or a string that parses to one).
 * @param {string} fieldName
 * @param {*}      value
 * @returns {string[]} Errors.
 */
function validateNumericId(fieldName, value) {
  const errors = [];
  if (value === undefined || value === null) return errors; // let validateRequired handle absence
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }
  return errors;
}

/**
 * Validate that `value` is a non-empty string within the given length bounds.
 * @param {string} fieldName
 * @param {*}      value
 * @param {number} minLen
 * @param {number} maxLen
 * @returns {string[]} Errors.
 */
function validateString(fieldName, value, minLen = 1, maxLen = Infinity) {
  const errors = [];
  if (value === undefined || value === null) return errors; // absence handled elsewhere
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  if (value.length < minLen) {
    errors.push(`"${fieldName}" must be at least ${minLen} character(s) long`);
  }
  if (value.length > maxLen) {
    errors.push(`"${fieldName}" must be at most ${maxLen} characters long`);
  }
  return errors;
}

/**
 * Validate that `value` is a string matching a standard email format.
 * Also enforces the RFC 5321 maximum address length of 254 characters.
 * @param {string} fieldName
 * @param {*}      value
 * @param {number} [maxLen=254]
 * @returns {string[]} Errors.
 */
function validateEmail(fieldName, value, maxLen = 254) {
  const errors = [];
  if (value === undefined || value === null) return errors; // absence handled elsewhere
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  if (value.length > maxLen) {
    errors.push(`"${fieldName}" must be at most ${maxLen} characters long`);
  }
  // RFC 5322-compatible regex (covers the vast majority of valid addresses)
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    errors.push(`"${fieldName}" must be a valid email address`);
  }
  return errors;
}

/**
 * Convenience: collect all validation errors for a user payload.
 * Fields checked: name (string, 1–100 chars), email (email format, max 254 chars).
 * @param {object}  body          - Request body.
 * @param {boolean} requireAll    - When true, both fields must be present.
 * @returns {string[]} All errors found.
 */
function validateUserBody(body, requireAll = true) {
  const errors = [];

  if (requireAll) {
    errors.push(...validateRequired(body, ['name', 'email']));
  }

  // Only type/length-check fields that are actually present to avoid duplicate errors
  if (body.name !== undefined && body.name !== null && body.name !== '') {
    errors.push(...validateString('name', body.name, 1, 100));
  }
  if (body.email !== undefined && body.email !== null && body.email !== '') {
    errors.push(...validateEmail('email', body.email, 254));
  }

  return errors;
}

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateEmail,
  validateUserBody,
};

