/**
 * Validation helper module.
 *
 * Each validator returns an array of error strings.
 * An empty array means the input is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

/**
 * Validate a user `id` supplied as a route parameter or query string value.
 * Accepts numeric strings (e.g. "42") as well as actual numbers.
 *
 * @param {*} id
 * @returns {string[]} validation errors
 */
function validateId(id) {
  const errors = [];
  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }
  if (!/^\d+$/.test(String(id))) {
    errors.push('id must be a positive integer');
  }
  return errors;
}

/**
 * Validate a `name` field from a request body.
 *
 * @param {*} name
 * @returns {string[]} validation errors
 */
function validateName(name) {
  const errors = [];
  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }
  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }
  const trimmed = name.trim();
  if (trimmed.length < MIN_NAME_LENGTH) {
    errors.push(`name must be at least ${MIN_NAME_LENGTH} character`);
  }
  if (trimmed.length > MAX_NAME_LENGTH) {
    errors.push(`name must be at most ${MAX_NAME_LENGTH} characters`);
  }
  return errors;
}

/**
 * Validate an `email` field from a request body.
 *
 * @param {*} email
 * @returns {string[]} validation errors
 */
function validateEmail(email) {
  const errors = [];
  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }
  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }
  if (email.length > MAX_EMAIL_LENGTH) {
    errors.push(`email must be at most ${MAX_EMAIL_LENGTH} characters`);
  }
  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }
  return errors;
}

/**
 * Validate a complete user body (name + email both required).
 * Used by POST /users.
 *
 * @param {object} body
 * @returns {string[]} validation errors
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a partial user body for updates (name and/or email are optional,
 * but at least one must be provided, and any supplied field must be valid).
 * Used by PUT /users/:id.
 *
 * @param {object} body
 * @returns {string[]} validation errors
 */
function validateUserUpdateBody(body) {
  const errors = [];
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return errors;
  }
  if (hasName) errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Middleware factory: validates request body fields, sends a 400 with all
 * errors if any are found, otherwise calls next().
 *
 * @param {function(object): string[]} validatorFn
 */
function bodyValidator(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req.body || {});
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

/**
 * Middleware: validates the `:id` route parameter, sends a 400 with all
 * errors if any are found, otherwise calls next().
 */
function idParamValidator(req, res, next) {
  const errors = validateId(req.params.id);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validateUserUpdateBody,
  bodyValidator,
  idParamValidator,
};

