// Validation helper module
// Provides reusable validators and a composable `validate` runner.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ── Individual field validators ───────────────────────────────────────────────

/**
 * Validate that a value is present (not undefined, null, or empty string).
 * @param {string} field  - field name used in error messages
 * @param {*}      value  - the value to check
 * @returns {string|null} error message or null if valid
 */
function validateRequired(field, value) {
  if (value === undefined || value === null || value === '') {
    return `"${field}" is required`;
  }
  return null;
}

/**
 * Validate that a value is a finite integer greater than 0.
 * Accepts both actual numbers and numeric strings (e.g. route params).
 * @param {string}        field
 * @param {number|string} value
 * @returns {string|null}
 */
function validateId(field, value) {
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `"${field}" must be a positive integer`;
  }
  return null;
}

/**
 * Validate that a value is a non-empty string.
 * @param {string} field
 * @param {*}      value
 * @returns {string|null}
 */
function validateString(field, value) {
  if (typeof value !== 'string') {
    return `"${field}" must be a string`;
  }
  return null;
}

/**
 * Validate string length falls within [min, max] (inclusive).
 * Assumes the value has already been confirmed to be a string.
 * @param {string} field
 * @param {string} value
 * @param {number} min
 * @param {number} max
 * @returns {string|null}
 */
function validateLength(field, value, min, max) {
  const len = value.length;
  if (len < min || len > max) {
    return `"${field}" must be between ${min} and ${max} characters`;
  }
  return null;
}

/**
 * Validate that a string matches a basic email format and is at most 254 chars.
 * Assumes the value has already been confirmed to be a string.
 * @param {string} field
 * @param {string} value
 * @returns {string|null}
 */
function validateEmail(field, value) {
  if (!EMAIL_REGEX.test(value)) {
    return `"${field}" must be a valid email address`;
  }
  if (value.length > 254) {
    return `"${field}" must be at most 254 characters`;
  }
  return null;
}

// ── Composite validators for common request shapes ────────────────────────────

/**
 * Run a list of validator functions, collect every error, and return them.
 * Each validator is a zero-argument function that returns a string (error) or
 * null (pass).
 *
 * @param  {...Function} validators
 * @returns {string[]}  array of error messages (empty = all passed)
 */
function runValidators(...validators) {
  const errors = [];
  for (const fn of validators) {
    const result = fn();
    if (result !== null) {
      errors.push(result);
    }
  }
  return errors;
}

/**
 * Validate a URL/route `id` parameter.
 * @param {string} id - raw string from req.params.id
 * @returns {string[]}
 */
function validateIdParam(id) {
  return runValidators(
    () => validateRequired('id', id),
    () => (id !== undefined && id !== null && id !== '' ? validateId('id', id) : null),
  );
}

/**
 * Validate a user creation payload (all fields required).
 * @param {{ name: *, email: * }} body
 * @returns {string[]}
 */
function validateCreateUser(body) {
  const { name, email } = body;
  return runValidators(
    // name
    () => validateRequired('name', name),
    () => (name !== undefined && name !== null ? validateString('name', name) : null),
    () => (typeof name === 'string' ? validateLength('name', name, 1, 100) : null),
    // email
    () => validateRequired('email', email),
    () => (email !== undefined && email !== null ? validateString('email', email) : null),
    () => (typeof email === 'string' ? validateEmail('email', email) : null),
  );
}

/**
 * Validate a user update payload (at least one field required, but each
 * provided field must be valid).
 * @param {{ name?: *, email?: * }} body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  const { name, email } = body;
  const errors = [];

  if (name === undefined && email === undefined) {
    errors.push('at least one field ("name" or "email") must be provided');
    return errors;
  }

  if (name !== undefined) {
    const nameErrors = runValidators(
      () => (name === null || name === '' ? validateRequired('name', name) : null),
      () => validateString('name', name),
      () => (typeof name === 'string' ? validateLength('name', name, 1, 100) : null),
    );
    errors.push(...nameErrors);
  }

  if (email !== undefined) {
    const emailErrors = runValidators(
      () => (email === null || email === '' ? validateRequired('email', email) : null),
      () => validateString('email', email),
      () => (typeof email === 'string' ? validateEmail('email', email) : null),
    );
    errors.push(...emailErrors);
  }

  return errors;
}

// ── Express middleware helper ─────────────────────────────────────────────────

/**
 * If `errors` is non-empty, send a 400 response with a descriptive body and
 * return `true` (so the caller can bail out early).  Otherwise return `false`.
 *
 * @param {string[]} errors
 * @param {import('express').Response} res
 * @returns {boolean}
 */
function sendValidationError(errors, res) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  // primitives (exported for unit testing)
  validateRequired,
  validateId,
  validateString,
  validateLength,
  validateEmail,
  runValidators,
  // composites
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
  // middleware helper
  sendValidationError,
};

