const {
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
  sendValidationError,
} = require('./validation');

const app = express();
app.use(express.json());

// ── In-memory data store ──────────────────────────────────────────────────────
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ── GET /health ───────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ── GET /users ────────────────────────────────────────────────────────────────
// No input to validate — returns all users.
app.get('/users', (req, res) => {
  res.json(users);
});

// ── GET /users/:id ────────────────────────────────────────────────────────────
// Validates: id is a positive integer.
app.get('/users/:id', (req, res) => {
  const errors = validateIdParam(req.params.id);
  if (sendValidationError(errors, res)) return;

  const user = users.find(u => u.id === Number(req.params.id));
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }
  res.json(user);
});

// ── POST /users ───────────────────────────────────────────────────────────────
// Validates: name (required, string, 1-100 chars),
//            email (required, string, valid format, max 254 chars).
app.post('/users', (req, res) => {
  const errors = validateCreateUser(req.body);
  if (sendValidationError(errors, res)) return;

  const newUser = { id: nextId++, name: req.body.name, email: req.body.email };
  users.push(newUser);
  res.status(201).json(newUser);
});

// ── PUT /users/:id ────────────────────────────────────────────────────────────
// Validates: id is a positive integer; at least one of name/email provided;
//            each provided field meets its type and length rules.
app.put('/users/:id', (req, res) => {
  const idErrors = validateIdParam(req.params.id);
  if (sendValidationError(idErrors, res)) return;

  const bodyErrors = validateUpdateUser(req.body);
  if (sendValidationError(bodyErrors, res)) return;

  const user = users.find(u => u.id === Number(req.params.id));
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  if (req.body.name  !== undefined) user.name  = req.body.name;
  if (req.body.email !== undefined) user.email = req.body.email;

  res.json(user);
});

// ── DELETE /users/:id ─────────────────────────────────────────────────────────
// Validates: id is a positive integer.
app.delete('/users/:id', (req, res) => {
  const errors = validateIdParam(req.params.id);
  if (sendValidationError(errors, res)) return;

  const idx = users.findIndex(u => u.id === Number(req.params.id));
  if (idx === -1) {
    return res.status(404).json({ error: 'User not found' });
  }

  const [deleted] = users.splice(idx, 1);
  res.json({ message: 'User deleted', user: deleted });
});

// ── Start ─────────────────────────────────────────────────────────────────────
app.listen(3000, () => {
  console.log('Server running on port 3000');
});

