/**
 * Validation helper module.
 *
 * Exports individual field validators and a higher-level buildValidator()
 * factory that composes them into an Express middleware function.
 *
 * Each validator returns an error string when the value is invalid, or null
 * when it is acceptable.  Returning null means "no error".
 */

'use strict';

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validates a numeric id coming from req.params.
 * Express always delivers route params as strings, so we accept either a
 * string representation of a positive integer or an actual number.
 */
function validateId(value) {
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `id must be a positive integer (received: ${JSON.stringify(value)})`;
  }
  return null;
}

/**
 * Validates a "name" field.
 *  – must be present
 *  – must be a string
 *  – must be between 1 and 100 characters
 */
function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return `name must be a string (received: ${typeof value})`;
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return 'name must be at least 1 character long';
  }
  if (trimmed.length > 100) {
    return `name must be at most 100 characters long (received: ${trimmed.length})`;
  }
  return null;
}

/**
 * Validates an optional "name" field – same rules as validateName but the
 * field may be omitted entirely.  If provided it still obeys all constraints.
 */
function validateNameOptional(value) {
  if (value === undefined || value === null) {
    return null; // optional – absence is fine
  }
  return validateName(value);
}

/**
 * Validates an "email" field.
 *  – must be present
 *  – must be a string
 *  – must match a standard email format
 *  – must be at most 254 characters (RFC 5321 limit)
 */
function validateEmail(value) {
  if (value === undefined || value === null) {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return `email must be a string (received: ${typeof value})`;
  }
  if (value.length > 254) {
    return `email must be at most 254 characters long (received: ${value.length})`;
  }
  // RFC 5322-ish regex: local-part @ domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `email must be a valid email address (received: ${JSON.stringify(value)})`;
  }
  return null;
}

/**
 * Validates an optional "email" field – same rules as validateEmail but the
 * field may be omitted entirely.
 */
function validateEmailOptional(value) {
  if (value === undefined || value === null) {
    return null; // optional – absence is fine
  }
  return validateEmail(value);
}

// ---------------------------------------------------------------------------
// Middleware factory
// ---------------------------------------------------------------------------

/**
 * buildValidator(schema) → Express middleware
 *
 * schema is a plain object whose keys map to validator functions:
 *
 *   {
 *     params: { id: validateId },
 *     body:   { name: validateName, email: validateEmail },
 *   }
 *
 * Supported source keys: "params", "body", "query".
 *
 * The middleware collects ALL validation errors and, if any are found,
 * responds immediately with HTTP 400 and a JSON body listing every failure:
 *
 *   { errors: ["name is required", "email must be a valid email address …"] }
 *
 * If there are no errors it calls next() to continue to the route handler.
 */
function buildValidator(schema) {
  return function validate(req, res, next) {
    const errors = [];

    for (const [source, fields] of Object.entries(schema)) {
      const data = req[source] || {};
      for (const [field, validator] of Object.entries(fields)) {
        const error = validator(data[field]);
        if (error) {
          errors.push(error);
        }
      }
    }

    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }

    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Individual validators (useful for unit tests and custom middleware)
  validateId,
  validateName,
  validateNameOptional,
  validateEmail,
  validateEmailOptional,

  // Middleware factory
  buildValidator,
};
